    srand((unsigned)time(NULL));
    int r = ssl3_connect();
    printf("%d\n", r);
    return 0;
}

#include <stdio.h>
#include <stdint.h>

typedef struct SSL {
    int s3_flags;
    unsigned int in_handshake;
    unsigned long flags;
    int ag_X;
    int ag_Y;
} SSL;

int ssl3_connect(SSL *s) {
    /* Assign constants (within 32-bit signed range) */
    s->s3_flags = 0;
    s->ag_X = 42;
    s->ag_Y = 17;

    /* Bitwise XOR (not an arithmetic overflow concern) */
    int xored = s->ag_X ^ s->ag_Y;

    /* Increment on unsigned int (well-defined modulo 2^32) */
    s->in_handshake = s->in_handshake + 1u;

    /* Cast to unsigned long before addition (unsigned arithmetic) */
    s->flags = (unsigned long)s->flags + (unsigned long)1;

    return xored;
}

int main(void) {
    SSL s;
    s.s3_flags = -1;
    s.in_handshake = 0u;
    s.flags = 0UL;
    s.ag_X = 0;
    s.ag_Y = 0;

    int res = ssl3_connect(&s);
    (void)res;
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

typedef struct ssl3_state {
    unsigned long flags;
} SSL3_STATE;

typedef struct ssl_ctx_stats {
    unsigned int sess_connect_renegotiate;
    unsigned int sess_connect;
    unsigned int sess_hit;
    unsigned int sess_connect_good;
} SSL_CTX_STATS;

typedef struct ssl_st {
    unsigned int s_in_handshake;
    unsigned int s_version;
    SSL3_STATE *s3;
    SSL_CTX_STATS *ctx_stats;
} SSL;

/* A simplified/annotated implementation that performs only the sorts of
   operations referenced by the proof: increments of unsigned counters,
   unsigned long arithmetic on flags, unsigned subtractions in comparisons,
   and an integer bitwise XOR. */
int ssl3_connect(SSL *s)
{
    unsigned long flags;
    unsigned long r1;
    unsigned long r2;
    unsigned long r3;
    unsigned int v0;
    unsigned int tmp1;
    unsigned int tmp2;
    int ag_X = 0x55AA55AA;
    int ag_Y = 0x0F0F0F0F;
    int ag_Z;

    if (s == NULL) return -1;
    if (s->s3 == NULL) return -1;

    /* increment an "in handshake" unsigned counter */
    s->s_in_handshake++;

    /* increment various unsigned context statistics counters if present */
    if (s->ctx_stats != NULL) {
        s->ctx_stats->sess_connect_renegotiate++;
        s->ctx_stats->sess_connect++;
        s->ctx_stats->sess_hit++;
        s->ctx_stats->sess_connect_good++;
    }

    /* unsigned long arithmetic on flags (examples from the proof) */
    flags = s->s3->flags;
    /* note: expressions like flags - (-5L) and flags + 4L are unsigned
       arithmetic when `flags` is unsigned long */
    r1 = flags - (-5L);
    r2 = flags + 4L;
    r3 = flags - 2L;

    (void)r1;
    (void)r2;
    (void)r3;

    /* unsigned subtractions / comparisons using unsigned fields */
    v0 = s->s_version - 65280u;
    tmp1 = v0 - 12288u;
    tmp2 = tmp1 - 16384u;
    (void)tmp1;
    (void)tmp2;

    /* bitwise XOR on signed ints (not an arithmetic overflow) */
    ag_Z = ag_X ^ ag_Y;
    (void)ag_Z;

    /* return success */
    return 1;
}

int main(void)
{
    SSL3_STATE s3 = { .flags = 0UL };
    SSL_CTX_STATS stats = {0,0,0,0};
    SSL s = { .s_in_handshake = 0U, .s_version = 0xFFFFU, .s3 = &s3, .ctx_stats = &stats };

    int ret = ssl3_connect(&s);
    printf("ssl3_connect returned %d\n", ret);
    printf("s_in_handshake=%u\n", s.s_in_handshake);
    printf("sess_connect=%u\n", s.ctx_stats->sess_connect);
    return 0;
}

#include <stdio.h>
#include <stdint.h>

int ssl3_connect(int mode, unsigned int seq) {
    /* This function intentionally avoids signed arithmetic that could overflow.
       All arithmetic on quantities that may wrap is done on unsigned integers.
       Signed integers are only assigned constants, compared, or used for XOR-like
       control (here kept to constants and comparisons). */
    int state = 0;             /* signed, only assigned constants and compared */
    unsigned int useq = seq;   /* unsigned, increments wrap modulo 2^32 */
    unsigned int flags = 0u;   /* unsigned flags manipulated with XOR */

    /* Set state based on mode (only comparisons and constant assignments) */
    if (mode < 0) {
        state = -1;
    } else if (mode == 0) {
        state = 0;
    } else {
        state = 1;
    }

    /* Toggle a flag using bitwise XOR on an unsigned value (no signed overflow) */
    flags ^= 1u;

    /* Advance sequence number using unsigned arithmetic (wraps modulo 2^32) */
    useq += 1u;

    /* Make a decision based on the (possibly wrapped) unsigned sequence number */
    if (useq == 0u) {
        /* assign a constant to the signed state (no arithmetic overflow) */
        state = 0;
    }

    /* Return one of the small constant states: -1, 0, or 1 */
    return state;
}

int main(void) {
    /* Example calls to ssl3_connect with safe arguments */
    int r1 = ssl3_connect(1, 0u);
    int r2 = ssl3_connect(0, 42u);
    int r3 = ssl3_connect(-1, 4294967295u); /* large unsigned wraps when incremented */

    printf("results: %d %d %d\n", r1, r2, r3);
    return 0;
}

#include <stdio.h>
#include <stdint.h>

unsigned int mix(unsigned int x, unsigned int y) {
    unsigned int z = x ^ y;
    z = z + (x << 3);
    z = z + (y >> 5);
    z = z ^ (z << 7);
    return z;
}

unsigned long combine(unsigned long a, unsigned long b) {
    unsigned long r = a ^ b;
    r = r + (a << 13);
    r = r + (b >> 17);
    r = r ^ (r << 23);
    return r;
}

int main(void) {
    unsigned int u1 = 123456789u;
    unsigned int u2 = 987654321u;
    unsigned int res1 = mix(u1, u2);

    unsigned long v1 = 0xFEDCBA9876543210ul;
    unsigned long v2 = 0x0123456789ABCDEFul;
    unsigned long res2 = combine(v1, v2);

    printf("%u %lu\n", res1, res2);
    return 0;
}

#include <stdio.h>
#include <stdint.h>

int ssl3_connect(void) {
    int state = 0;        // assignment of constant (signed)
    int err = 0;          // assignment of constant (signed)
    int mask = 0xFF;      // assignment of constant (signed)

    // bitwise XOR on signed ints (cannot overflow)
    int result = state ^ mask;

    // comparisons on signed ints (cannot overflow)
    if (result < 0) {
        err = -1;         // assignment of constant (signed)
        return err;
    }

    // All arithmetic below is on unsigned types (wraps modulo, no signed overflow)
    unsigned int u1 = 0u;
    unsigned long u2 = 0ul;

    u1 = u1 + 42u;
    u2 = u2 + 100ul;
    u1 = u1 - 1u;

    (void)u2; // silence unused warning

    if (state == 0) {
        state = 1;        // assignment of constant (signed)
    }

    return state;
}

int main(void) {
    int r = ssl3_connect();
    printf("%d\n", r);
    return 0;
}

