#include <stdio.h>
#include <stdlib.h>

int hanoi(int n) {
    int res = 1;
    for (int i = 1; i < n; ++i) {
        res = res * 2 + 1;
    }
    return res;
}

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 1;
    if (n < 1 || n > 31) {
        fprintf(stderr, "n must be between 1 and 31\n");
        return 1;
    }
    int moves = hanoi(n);
    printf("%d\n", moves);
    return 0;
}

#include <stdio.h>
#include <stdint.h>

int counter = 0;

int hanoi(int n) {
    /* compute 2^n - 1 safely using unsigned shift */
    uint32_t v = (uint32_t)1u << n;
    return (int)(v - 1u);
}

void applyHanoi(int n) {
    counter += hanoi(n);
}

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;
    /* require 1 <= n <= 31 */
    if (n < 1 || n > 31) return 0;
    applyHanoi(n);
    printf("%d\n", counter);
    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <inttypes.h>
#include <assert.h>

int32_t hanoi(int n) {
    if (n <= 0) return 0;
    if (n == 1) return 1;
    return 2 * hanoi(n - 1) + 1;
}

int32_t applyHanoi(int n) {
    if (n <= 0) return 0;
    return 1 + 2 * applyHanoi(n - 1);
}

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 1;
    assert(1 <= n && n <= 31);
    int32_t h = hanoi(n);
    int32_t a = applyHanoi(n);
    assert(h == a);
    assert(h <= INT32_MAX);
    printf("%" PRId32 "\n", h);
    return 0;
}

