#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>

int hanoiNat(unsigned n) {
    /* compute 2^n - 1 using 32-bit unsigned arithmetic (safe for n <= 31) */
    uint32_t res = ((uint32_t)1 << n) - 1u;
    return (int)res;
}

int applyHanoi(unsigned n) {
    /* recursive definition: applyHanoi(0) = 0; applyHanoi(n+1) = 1 + applyHanoi(n) + applyHanoi(n) */
    if (n == 0) return 0;
    int half = applyHanoi(n - 1);
    return 1 + half + half;
}

int main(int argc, char **argv) {
    if (argc != 2) {
        fprintf(stderr, "Usage: %s n (1 <= n <= 31)\n", argv[0]);
        return 1;
    }
    char *end;
    long nl = strtol(argv[1], &end, 10);
    if (*end != '\0' || nl < 1 || nl > 31) {
        fprintf(stderr, "n must be an integer between 1 and 31\n");
        return 1;
    }
    unsigned n = (unsigned)nl;
    int nat = hanoiNat(n);
    int rec = applyHanoi(n);
    if (nat != rec) {
        fprintf(stderr, "Error: mismatch hanoiNat=%d applyHanoi=%d\n", nat, rec);
        return 2;
    }
    printf("%d\n", nat);
    return 0;
}

