#include <stdio.h>

int hanoi(int n) {
    if (n == 0) return 0;
    if (n == 1) return 1;
    return 2 * hanoi(n - 1) + 1;
}

int counter;

void applyHanoi(int n) {
    if (n == 0) return;
    counter++;
    applyHanoi(n - 1);
    applyHanoi(n - 1);
}

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 1;
    printf("%d\n", hanoi(n));
    counter = 0;
    applyHanoi(n);
    printf("%d\n", counter);
    return 0;
}

