    int32_t c = 0;
    int32_t k;

    // initial state (0,0,0)
    for (i = 0; i <= 9; ++i) {
        int32_t baseC = 9 * i;
        for (k = 0; k < 9; ++k) {
            j = 3 + k;
            c = baseC + k;
            j = 2 + k;
            c = baseC + k + 1;
        }
        j = 12;
