#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

typedef struct {
    int32_t a;
    int32_t b;
    int32_t c;
} State;

int main(void) {
    // maximum needed: for each i (0..9) inner produces 9*4 + 1 = 37 states,
    // so 10*37 = 370, plus outer final (10,12,c) and initial (0,0,0) -> safe to allocate 400
    size_t cap = 400;
    State *v = (State*)malloc(cap * sizeof(State));
    if (!v) return 1;
    size_t n = 0;

    int32_t c = 0;
    for (int i = 0; i < 10; ++i) {
        for (int j = 3; j < 12; ++j) {
            State s1 = { (int32_t)i, (int32_t)j, c };
            State s2 = { (int32_t)i, (int32_t)(j - 1), c };
            State s3 = { (int32_t)i, (int32_t)(j - 1), (int32_t)(c + 1) };
            State s4 = { (int32_t)i, (int32_t)(j + 1), (int32_t)(c + 1) };
            // push in chronological order; final list will be printed in reverse to emulate cons
            if (n + 4 >= cap) {
                cap *= 2;
                v = (State*)realloc(v, cap * sizeof(State));
                if (!v) return 1;
            }
            v[n++] = s4;
            v[n++] = s3;
            v[n++] = s2;
            v[n++] = s1;
            c = c + 1;
        }
        // push (i,12,c) as in the functional code's base case for inner
        if (n + 1 >= cap) {
            cap *= 2;
            v = (State*)realloc(v, cap * sizeof(State));
            if (!v) return 1;
        }
        v[n++] = (State){ (int32_t)i, 12, c };
    }
    // outer finally conses (10,12,c)
    if (n + 1 >= cap) {
        cap *= 2;
        v = (State*)realloc(v, cap * sizeof(State));
        if (!v) return 1;
    }
    v[n++] = (State){ 10, 12, c };

    // all_states = (0,0,0) :: simulate
    // Print (0,0,0) first, then simulate in the cons order (which is reverse of chronological vector)
    printf("%d %d %d\n", 0, 0, 0);
    for (ssize_t idx = (ssize_t)n - 1; idx >= 0; --idx) {
        printf("%d %d %d\n", (int)v[idx].a, (int)v[idx].b, (int)v[idx].c);
    }

    free(v);
    return 0;
}

