#include <stdio.h>
#include <stdint.h>
#include <inttypes.h>

typedef struct {
    int32_t x;
    int32_t y;
    int32_t z;
} State;

void step(State *s) {
    int32_t oldy = s->y;
    s->x = s->x + s->z;
    s->y = s->y + 1;
    s->z = -2 * oldy;
}

State init_state(void) {
    State s;
    s.x = -1;
    s.y = 1;
    s.z = -1;
    return s;
}

State run(unsigned n) {
    State s = init_state();
    for (unsigned i = 0; i < n; ++i) step(&s);
    return s;
}

int main(void) {
    unsigned n = 46341;
    State s = run(n);

    /* compute the next step in 64-bit to detect overflow wrt 32-bit bounds */
    int64_t next_x = (int64_t)s.x + (int64_t)s.z;
    int64_t next_y = (int64_t)s.y + 1;
    int64_t next_z = -2 * (int64_t)s.y;

    int overflow = 0;
    if (next_x < INT32_MIN || next_x > INT32_MAX) overflow = 1;
    if (next_y < INT32_MIN || next_y > INT32_MAX) overflow = 1;
    if (next_z < INT32_MIN || next_z > INT32_MAX) overflow = 1;

    if (overflow) {
        printf("overflow detected for next step\n");
        printf("next_x=%" PRId64 " next_y=%" PRId64 " next_z=%" PRId64 "\n", next_x, next_y, next_z);
    } else {
        printf("no overflow for next step\n");
        printf("next_x=%" PRId64 " next_y=%" PRId64 " next_z=%" PRId64 "\n", next_x, next_y, next_z);
    }

    return 0;
}

