#include <stdbool.h>
#include <inttypes.h>

struct State {
    int32_t x;
    int32_t y;
};

static inline bool is_in_range(int64_t n) {
    return n >= INT32_MIN && n <= INT32_MAX;
}

/* Compute the state transition:
   new.x = s.x + s.y
   new.y = -2 * s.y - 1
   Returns true on success (no overflow), false if result out of 32-bit range. */
bool step(struct State s, struct State *out) {
    int64_t nx = (int64_t)s.x + (int64_t)s.y;
    int64_t ny = -2 * (int64_t)s.y - 1;
    if (!is_in_range(nx) || !is_in_range(ny)) return false;
    out->x = (int32_t)nx;
    out->y = (int32_t)ny;
    return true;
}

int main(void) {
    struct State s;
    if (scanf("%" SCNd32 " %" SCNd32, &s.x, &s.y) != 2) {
        fprintf(stderr, "Expected two 32-bit integers as input\n");
        return 1;
    }

    struct State t;
    if (step(s, &t)) {
        printf("%" PRId32 " %" PRId32 "\n", t.x, t.y);
        return 0;
    } else {
        fprintf(stderr, "Overflow: result out of 32-bit signed range\n");
        return 2;
    }
}

#include <stdint.h>
#include <stdio.h>
#include <inttypes.h>
#include <assert.h>

void run(int32_t x, int32_t y) {
    while (x >= 0) {
        int64_t sum = (int64_t)x + (int64_t)y;
        int64_t nexty = -2 * (int64_t)y - 1;
        assert(sum >= INT32_MIN && sum <= INT32_MAX);
        assert(nexty >= INT32_MIN && nexty <= INT32_MAX);
        x = (int32_t)sum;
        y = (int32_t)nexty;
    }
    printf("Loop exited with x=%" PRId32 " y=%" PRId32 "\n", x, y);
}

int main(void) {
    int64_t a, b;
    if (scanf("%" SCNd64 " %" SCNd64, &a, &b) != 2) return 1;
    int32_t x = (int32_t)a;
    int32_t y = (int32_t)b;
    run(x, y);
    return 0;
}

