int main(void) {
    int z;
    if (scanf("%d", &z) != 1) return 1;

    int x = 1;
    int y = z;
    int c = 1;

    /* Loop performs the step:
       x := x*z + 1;
       y := y*z;
       c := c + 1;
       The invariant x*(z-1) == y-1 holds initially and is preserved. */
    for (int i = 0; i < 5; ++i) {
        x = x * z + 1;
        y = y * z;
        c = c + 1;
    }

    printf("%d %d %d\n", x, y, c);
    return 0;
}

