#include <stdio.h>
#include <stdlib.h>
#include <gmp.h>

/*
  This program verifies the identity
    (z - 1) * (sum_{i=0}^{k-1} z^i) = z^k - 1
  for arbitrary-precision integer z and nonnegative integer k.

  Usage: ./geom z k
    z - integer (decimal)
    k - nonnegative integer (decimal)
*/

int main(int argc, char **argv) {
    if (argc != 3) {
        fprintf(stderr, "Usage: %s z k\n", argv[0]);
        return 1;
    }

    mpz_t z, sum, cur, lhs, rhs, zpowk, zminus1;
    unsigned long long k;

    if (mpz_init(z), mpz_init(sum), mpz_init(cur),
        mpz_init(lhs), mpz_init(rhs), mpz_init(zpowk),
        mpz_init(zminus1), 0) {
        /* noop - initializations above */
    }

    if (mpz_set_str(z, argv[1], 10) != 0) {
        fprintf(stderr, "Invalid integer for z: %s\n", argv[1]);
        return 1;
    }

    char *endptr = NULL;
    k = strtoull(argv[2], &endptr, 10);
    if (endptr == argv[2] || *endptr != '\0') {
        fprintf(stderr, "Invalid nonnegative integer for k: %s\n", argv[2]);
        return 1;
    }

    mpz_set_ui(sum, 0);
    mpz_set_ui(cur, 1); /* cur = z^0 */

    for (unsigned long long i = 0; i < k; ++i) {
        mpz_add(sum, sum, cur);    /* sum += cur */
        mpz_mul(cur, cur, z);     /* cur *= z */
    }

    mpz_sub_ui(zpowk, 0, 0); /* ensure initialized value overwritten by pow next */
    mpz_pow_ui(zpowk, z, k); /* zpowk = z^k */

    mpz_sub_ui(rhs, zpowk, 1);      /* rhs = z^k - 1 */
    mpz_sub_ui(zminus1, z, 1);     /* zminus1 = z - 1 */
    mpz_mul(lhs, zminus1, sum);    /* lhs = (z - 1) * sum */

    gmp_printf("z = %Zd\nk = %llu\n", z, k);
    gmp_printf("sum_{i=0}^{k-1} z^i = %Zd\n", sum);
    gmp_printf("(z - 1) * sum = %Zd\n", lhs);
    gmp_printf("z^k - 1 = %Zd\n", rhs);

    if (mpz_cmp(lhs, rhs) == 0) {
        printf("Identity holds.\n");
    } else {
        printf("Identity does NOT hold.\n");
    }

    mpz_clear(z);
    mpz_clear(sum);
    mpz_clear(cur);
    mpz_clear(lhs);
    mpz_clear(rhs);
    mpz_clear(zpowk);
    mpz_clear(zminus1);

    return 0;
}

