#include <stdio.h>
#include <stdlib.h>

int main(int argc, char **argv) {
    if (argc < 3) {
        fprintf(stderr, "Usage: %s z n\n", argv[0]);
        return 1;
    }

    long long z = atoll(argv[1]);
    long long n = atoll(argv[2]);
    if (n < 0) {
        fprintf(stderr, "n must be non-negative\n");
        return 1;
    }

    long long x = 1;
    long long y = z;
    long long c = 1;

    for (long long i = 0; i < n; ++i) {
        long long nx = x * z + 1;
        long long ny = y * z;
        x = nx;
        y = ny;
        c = c + 1;
    }

    /* Final assertion: 1 + x * (z - 1) - y == 0 */
    if (1 + x * (z - 1) - y != 0) {
        fprintf(stderr, "Assertion failed: 1 + x*(z-1) - y != 0\n");
        return 2;
    }

    printf("x=%lld y=%lld c=%lld\n", x, y, c);
    return 0;
}

