#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

/*
  C `int` range: [INT_MIN, INT_MAX] == [-2^31, 2^31 - 1] on typical platforms
  This program implements the recursive loop proven in the Lean file:
    void loop(int a, int b) {
      if (a > b) {
        b = b + a;
        a = a + 1;
        loop(a, b);
      }
    }
  The implementation checks for overflow before performing the additions.
*/

void loop(int a, int b) {
    if (a > b) {
        /* Check that a + b fits in int */
        long long sum_ab = (long long)a + (long long)b;
        if (sum_ab < INT_MIN || sum_ab > INT_MAX) {
            fprintf(stderr, "Integer overflow detected for a + b\n");
            exit(EXIT_FAILURE);
        }
        /* Check that a + 1 fits in int */
        long long inc_a = (long long)a + 1;
        if (inc_a < INT_MIN || inc_a > INT_MAX) {
            fprintf(stderr, "Integer overflow detected for a + 1\n");
            exit(EXIT_FAILURE);
        }

        b = (int)sum_ab;
        a = (int)inc_a;
        loop(a, b);
    }
}

int main(void) {
    int a, b;
    if (scanf("%d %d", &a, &b) != 2) {
        fprintf(stderr, "Please provide two integers as input.\n");
        return EXIT_FAILURE;
    }
    loop(a, b);
    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <limits.h>

int main(void) {
    int a, b;
    if (scanf("%d %d", &a, &b) != 2) return 1;

    /* Preconditions expected by the verified proof (not enforced here):
       - a and b fit in 32-bit int (true by types)
       - a > b
       - a <= 0 and b <= 0
       - b + a >= INT_MIN (no underflow)
       Under these conditions the following two operations are safe:
         b = b + a;
         a = a + 1;
    */

    b = b + a;
    a = a + 1;

    printf("%d %d\n", a, b);
    return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <inttypes.h>
#include <limits.h>
#include <inttypes.h>
#include <stdlib.h>
#include <assert.h>

int main(void) {
    int32_t a, b;
    if (scanf("%" SCNd32 " %" SCNd32, &a, &b) != 2) {
        return 1;
    }

    /* Preconditions corresponding to the Lean proof:
       -I_MAX ≤ a ≤ 0 and -I_MAX ≤ b ≤ 0, where I_MAX = 2147483647
       and a + b ≥ I_MIN (I_MIN = -2147483648).
    */
    assert((int64_t)(-2147483647) <= a && a <= 0);
    assert((int64_t)(-2147483647) <= b && b <= 0);
    assert((int64_t)a + (int64_t)b >= (int64_t)INT32_MIN);

    if (a > b) {
        int32_t sum = a + b;    /* safe under the above precondition */
        int32_t inc = a + 1;    /* safe under the above precondition */
        printf("sum: %" PRId32 ", a+1: %" PRId32 "\n", sum, inc);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <limits.h>
#include <stdint.h>

int main(void) {
    /* seed RNG */
    srand((unsigned)time(NULL));

    /* random() returns a value in [0, INT_MAX] */
    unsigned mod = (unsigned)INT_MAX + 1u;
    int a = - (int)((unsigned)rand() % mod);
    int b = - (int)((unsigned)rand() % mod);

    /* safety check corresponding to the verified precondition */
    if ((int64_t)b + (int64_t)a < (int64_t)INT_MIN) {
        /* unsafe: exit */
        return 1;
    }

    while (a > b) {
        int sum = b + a; /* b + a proven safe under the precondition */
        (void)sum;       /* use sum to avoid unused-variable warnings */
        a = a + 1;       /* a + 1 proven safe under the precondition */
    }

    printf("%d %d\n", a, b);
    return 0;
}

#include <stdio.h>
#include <limits.h>

int main(void) {
    int r1, r2;
    if (scanf("%d %d", &r1, &r2) != 2) return 1;
    if (r1 < 0 || r2 < 0) return 1;

    int a = -r1;
    int b = -r2;

    while (a > b) {
        /* checks corresponding to the proof obligations to avoid overflow */
        if ((long)b + (long)a < INT_MIN || (long)b + (long)a > INT_MAX) break;
        if ((long)a + 1 > INT_MAX) break;

        b = b + a;
        a = a + 1;
    }

    printf("%d %d\n", a, b);
    return 0;
}

