#include <stdio.h>
#include <stdlib.h>
#include <time.h>

void loop(int *a, int *b) {
    if (*a > *b) return;
    if (*a < 0) {
        (*a)++;
    } else if (*b > -100) {
        (*b)--;
    }
    loop(a, b);
}

int main(void) {
    srand((unsigned)time(NULL));
    int a = - (rand() % 101); /* yields values in [-100, 0] */
    int b = - (rand() % 101); /* yields values in [-100, 0] */

    loop(&a, &b); /* ensure a > b while preserving the [-100,0] bounds */

    int sum = a + b;
    int inc = a + 1;
    printf("%d %d\n", sum, inc);
    return 0;
}

