#include <stdio.h>
#include <stdint.h>
#include <limits.h>

int main(void) {
    long long y = 0;
    long long x = 0;
    long long c = 0;

    for (int i = 0; i < 215; ++i) {
        long long y2 = y * y;
        long long y3 = y2 * y;
        long long y4 = y2 * y2;
        long long cond = 4 * x - y4 - 2 * y3 - y2;
        if (cond == 0) {
            y = y + 1;
            long long yn = y;
            x = x + yn * yn * yn;
            c = c + 1;
        }
    }

    if (4 * x > INT_MAX) {
        printf("overflow detected after 215 iterations: y=%lld x=%lld c=%lld\n", y, x, c);
    } else {
        printf("no overflow: y=%lld x=%lld c=%lld\n", y, x, c);
    }

    return 0;
}

