#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

void reach_error() {
    fprintf(stderr, "reach_error\n");
    abort();
}

void __VERIFIER_assert(int cond) {
    if (!cond) reach_error();
}

int main(int argc, char **argv) {
    if (argc < 2) {
        fprintf(stderr, "Usage: %s N\n", argv[0]);
        return 1;
    }

    long N_long = strtol(argv[1], NULL, 10);
    if (N_long <= 0) return 0;
    if (N_long > INT_MAX) return 0;
    int N = (int)N_long;

    /* Check bound as in the proof (assuming sizeof(int) = 4) */
    if (!(N > 0 && (long)N <= 2147483647L / (long)sizeof(int))) return 0;

    int *a = malloc((size_t)N * sizeof(int));
    if (!a) return 0;

    /* initialize all elements to 1 */
    for (int i = 0; i < N; ++i) a[i] = 1;

    /* first sum */
    long long sum = 0;
    for (int i = 0; i < N; ++i) sum += a[i];

    /* add sum to each element */
    for (int i = 0; i < N; ++i) a[i] = (int)((long long)a[i] + sum);

    /* reset and compute sum again */
    sum = 0;
    for (int i = 0; i < N; ++i) sum += a[i];

    /* add this sum to each element */
    for (int i = 0; i < N; ++i) a[i] = (int)((long long)a[i] + sum);

    long long expected = (long long)(N + 1) * (long long)(N + 1);

    /* final assertion for each element */
    for (int i = 0; i < N; ++i) {
        __VERIFIER_assert((long long)a[i] == expected);
    }

    free(a);
    return 0;
}

