    long long sum = 0;
    for (long long i = 0; i < N; ++i) sum += a[i];

    for (long long i = 0; i < N; ++i) a[i] += sum;

    sum = 0;
    for (long long i = 0; i < N; ++i) sum += a[i];

    for (long long i = 0; i < N; ++i) a[i] += sum;

    long long expected = (N + 1) * (N + 1);
    for (long long i = 0; i < N; ++i) {
        assert(a[i] == expected);
    }

    free(a);
    return 0;
}

#include <stdlib.h>
#include <stdio.h>

extern int __VERIFIER_nondet_int(void);

void reach_error() {
  /* indicate an error (for verifiers) */
  abort();
}

void __VERIFIER_assert(int cond) {
  if (!cond) reach_error();
}

int main(void) {
  int N = __VERIFIER_nondet_int();
  if (N <= 0) return 0;

  long long n = N;
  long long *a = (long long*)malloc(sizeof(long long) * N);
  if (!a) return 0;

  for (int i = 0; i < N; ++i) a[i] = 1;

  long long sum1 = 0;
  for (int i = 0; i < N; ++i) sum1 += a[i];

  for (int i = 0; i < N; ++i) a[i] += sum1;

  long long sum2 = 0;
  for (int i = 0; i < N; ++i) sum2 += a[i];

  for (int i = 0; i < N; ++i) a[i] += sum2;

  for (int i = 0; i < N; ++i) {
    __VERIFIER_assert(a[i] == (n + 1) * (n + 1));
  }

  free(a);
  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <assert.h>

int main(void) {
    long long N;
    if (scanf("%lld", &N) != 1) return 0;
    if (N <= 0) return 0;

    long long *a = malloc(sizeof(long long) * (size_t)N);
    if (!a) return 1;

    // First loop: set a[i] = 1
    for (long long i = 0; i < N; ++i) {
        a[i] = 1;
    }

    // Second loop: sum = sum of a[i] (should be N)
    long long sum = 0;
    for (long long i = 0; i < N; ++i) {
        sum += a[i];
    }

    // Third loop: set a[i] = a[i] + sum (1 + N)
    for (long long i = 0; i < N; ++i) {
        a[i] = a[i] + sum;
    }

    // Fourth loop: sum = sum of a[i] (N * (1 + N))
    sum = 0;
    for (long long i = 0; i < N; ++i) {
        sum += a[i];
    }

    // Fifth loop: set a[i] = a[i] + sum ((1+N)^2)
    for (long long i = 0; i < N; ++i) {
        a[i] = a[i] + sum;
    }

    // Assertion: every a[i] == (N + 1) * (N + 1)
    long long expected = (N + 1) * (N + 1);
    for (long long i = 0; i < N; ++i) {
        assert(a[i] == expected);
    }

    free(a);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <assert.h>

int main(int argc, char **argv) {
    if (argc < 2) {
        fprintf(stderr, "Usage: %s N\n", argv[0]);
        return 1;
    }

    long long N = atoll(argv[1]);
    if (N <= 0) {
        fprintf(stderr, "N must be > 0\n");
        return 1;
    }

    long long *a = malloc((size_t)N * sizeof(long long));
    long long *sum = malloc(sizeof(long long));
    if (!a || !sum) {
        fprintf(stderr, "Allocation failed\n");
        free(a);
        free(sum);
        return 1;
    }

    // First loop: a[i] = 1
    for (long long i = 0; i < N; ++i) a[i] = 1;

    // Second loop: sum[0] = sum(a[i]) = N
    sum[0] = 0;
    for (long long i = 0; i < N; ++i) sum[0] += a[i];

    // Third loop: a[i] = a[i] + sum[0] = 1 + N
    for (long long i = 0; i < N; ++i) a[i] += sum[0];

    // Fourth loop: sum[0] = sum(a[i]) = N * (N + 1)
    sum[0] = 0;
    for (long long i = 0; i < N; ++i) sum[0] += a[i];

    // Fifth loop: a[i] = a[i] + sum[0] = (N + 1)^2
    for (long long i = 0; i < N; ++i) a[i] += sum[0];

    // Sixth loop: assert a[i] == (N + 1)^2
    for (long long i = 0; i < N; ++i) {
        assert(a[i] == (N + 1) * (N + 1));
    }

    printf("All assertions passed for N=%lld\n", N);

    free(a);
    free(sum);
    return 0;
}

