int main(void) {
    int N;
    if (scanf("%d", &N) != 1) return 0;
    if (N <= 0) return 0;

    long long *a = malloc((size_t)N * sizeof(long long));
    if (!a) return 1;

    // 1. Initialize a[i] = 1 for all i
    for (int i = 0; i < N; ++i) a[i] = 1;

    // 2. Compute sum1 = sum(a[i])
    long long sum = 0;
    for (int i = 0; i < N; ++i) sum += a[i];

    // 3. Update a[i] = a[i] + sum1
    for (int i = 0; i < N; ++i) a[i] += sum;

    // 4. Compute sum2 = sum(a[i])
    sum = 0;
    for (int i = 0; i < N; ++i) sum += a[i];

    // 5. Update a[i] = a[i] + sum2
    for (int i = 0; i < N; ++i) a[i] += sum;

    // 6. Assert a[i] == (N+1)*(N+1) for all i
    long long target = (long long)(N + 1) * (long long)(N + 1);
    for (int i = 0; i < N; ++i) {
        if (a[i] != target) reach_error();
    }

    free(a);
    return 0;
}

