    if (a == NULL) return 1;

    for (int i = 0; i < N; ++i) a[i] = 1;

    long long sum = 0;
    for (int i = 0; i < N; ++i) sum += a[i]; /* sum == N */

    for (int i = 0; i < N; ++i) a[i] = a[i] + sum; /* a[i] == 1 + N */

    sum = 0;
    for (int i = 0; i < N; ++i) sum += a[i]; /* sum == N * (1 + N) */

    for (int i = 0; i < N; ++i) a[i] = a[i] + sum; /* a[i] == (N+1)^2 */

    long long expected = (long long)(N + 1) * (long long)(N + 1);
    for (int i = 0; i < N; ++i) {
        assert(a[i] == expected);
    }

    free(a);
    return 0;
}

