#include <stdio.h>
#include <stdlib.h>
#include <assert.h>

int main(int argc, char **argv) {
    long long N = 10;
    if (argc > 1) N = atoll(argv[1]);
    if (N < 0) N = 0;

    long long *a = malloc((size_t)N * sizeof *a);
    if (N > 0 && a == NULL) {
        perror("malloc");
        return 1;
    }

    // initArray: all entries = 1
    for (long long i = 0; i < N; ++i) a[i] = 1;

    // firstSum = sum of initArray
    long long firstSum = 0;
    for (long long i = 0; i < N; ++i) firstSum += a[i];

    // afterFirstAdd: add firstSum to each element
    for (long long i = 0; i < N; ++i) a[i] = a[i] + firstSum;

    // secondSum = sum of afterFirstAdd
    long long secondSum = 0;
    for (long long i = 0; i < N; ++i) secondSum += a[i];

    // afterSecondAdd: add secondSum to each element
    for (long long i = 0; i < N; ++i) a[i] = a[i] + secondSum;

    long long expected = (N + 1) * (N + 1);
    for (long long i = 0; i < N; ++i) {
        assert(a[i] == expected);
    }

    if (N == 0) {
        printf("N = 0, no elements to check.\n");
    } else {
        printf("All %lld elements equal %lld\n", N, expected);
    }

    free(a);
    return 0;
}

