  unsigned long long b = 1;  // b(0) = 1
  for (unsigned long long k = 0; k < n; ++k) {
    b += a;   // b(k+1) = b(k) + a(k)
    a += 10;  // a(k+1) = a(k) + 10
  }
  return b;
}

