import Mathlib

def f1 (x y : ℕ) : ℕ × ℕ := (0, x + y)
def f2 (x z : ℕ) : ℕ × ℕ := (x + z, 0)
def f3 (y z : ℕ) : ℕ × ℕ := (0, z + y)
def f4 (x y : ℕ) : ℕ × ℕ := (0, x + y)
def f5 (x z : ℕ) : ℕ × ℕ := (x + z, 0)
def f6 (y z : ℕ) : ℕ × ℕ := (0, z + y)

def run (n : ℕ) : ℕ × ℕ × ℕ :=
  let x := n; let y := 0;
  let (x1, y1) := f1 x y;
  let z1 := y1;
  let (x2, z2) := f2 x1 z1;
  let y2 := y1;
  let (y3, z3) := f3 y2 z2;
  let x3 := x2;
  let (x4, y4) := f4 x3 y3;
  let z4 := z3;
  let (x5, z5) := f5 x4 z4;
  let y5 := y4;
  let (y6, z6) := f6 y5 z5;
  (x5, y6, z6)

lemma run_spec (n : ℕ) : (run n).2.2 = n := by
  simp [run, f1, f2, f3, f4, f5, f6]

