import Mathlib

open Nat

structure State where
  x : Nat
  y : Nat
  z : Nat

def step1 (s : State) : State :=
  { x := 0, y := s.x + s.y, z := s.z }

def step2 (s : State) : State :=
  { x := s.x + s.z, y := s.y, z := 0 }

def step3 (s : State) : State :=
  { x := s.x, y := 0, z := s.y + s.z }

def step4 (s : State) : State :=
  { x := 0, y := s.x + s.y, z := s.z }

def step5 (s : State) : State :=
  { x := s.x + s.z, y := s.y, z := 0 }

def step6 (s : State) : State :=
  { x := s.x, y := 0, z := s.y + s.z }

def main_state (n : Nat) (z0 : Nat) : State :=
  let s0 : State := { x := n, y := 0, z := z0 }
  let s1 := step1 s0
  let s2 : State := { s1 with z := s1.y }
  let s3 := step2 s2
  let s4 := step3 s3
  let s5 := step4 s4
  let s6 := step5 s5
  let s7 := step6 s6
  s7

theorem main_correct (n : Nat) (z0 : Nat) : (main_state n z0).z = n := by
  unfold main_state step1 step2 step3 step4 step5 step6
  simp

