    printf("%llu\n", (unsigned long long)s7.z);
    return 0;
}

#include <assert.h>
#include <stdio.h>
#include <stdlib.h>

int main(int argc, char **argv) {
    unsigned int n = (argc > 1) ? (unsigned int)strtoul(argv[1], NULL, 10) : 0;
    unsigned int x = n, y = 0, z = 0;

    /* step1: while x>0: x--, y++ */
    while (x > 0) { x--; y++; }

    /* step2: while z>0: x++, z-- */
    while (z > 0) { x++; z--; }

    /* step3: while y>0: y--, z++ */
    while (y > 0) { y--; z++; }

    /* repeat the three steps */
    while (x > 0) { x--; y++; }
    while (z > 0) { x++; z--; }
    while (y > 0) { y--; z++; }

    assert(z == n);
    printf("%u\n", z);
    return 0;
}

#include <stdio.h>

int main(void) {
    unsigned long long n;
    if (scanf("%llu", &n) != 1) return 1;

    unsigned long long x = n, y = 0, z = 0;

    // loop1: while x > 0: x--, y++
    while (x > 0) { x--; y++; }

    // z := y
    z = y;

    // loop2: while z > 0: x++, z--
    while (z > 0) { x++; z--; }

    // call loop3 with z = 0
    z = 0;
    // loop3: while y > 0: y--, z++
    while (y > 0) { y--; z++; }

    // loop4: while x > 0: x--, y++
    while (x > 0) { x--; y++; }

    // loop5: while z > 0: x++, z--
    while (z > 0) { x++; z--; }

    // loop6: while y > 0: y--, z++
    while (y > 0) { y--; z++; }

    // print the third component (z)
    printf("%llu\n", z);
    return 0;
}

#include <stdio.h>

void loop1(long long *x, long long *y) {
    while (*x > 0) {
        (*x)--;
        (*y)++;
    }
}

void loop2(long long *x, long long *z) {
    while (*z > 0) {
        (*x)++;
        (*z)--;
    }
}

void loop3(long long *y, long long *z) {
    while (*y > 0) {
        (*y)--;
        (*z)++;
    }
}

void loop4(long long *x, long long *y) {
    while (*x > 0) {
        (*x)--;
        (*y)++;
    }
}

void loop5(long long *x, long long *z) {
    while (*z > 0) {
        (*x)++;
        (*z)--;
    }
}

void loop6(long long *y, long long *z) {
    while (*y > 0) {
        (*y)--;
        (*z)++;
    }
}

int main(void) {
    long long n;
    if (scanf("%lld", &n) != 1) return 1;

    long long x1 = n, y1 = 0;
    loop1(&x1, &y1);   // (x1,y1) = loop1(n,0)
    long long z1 = y1;

    long long x2 = x1, z2 = z1;
    loop2(&x2, &z2);   // (x2,z2) = loop2(x1,z1)

    long long y3 = y1, z3 = z2;
    loop3(&y3, &z3);   // (y3,z3) = loop3(y1,z2)

    long long x4 = x2, y4 = y3;
    loop4(&x4, &y4);   // (x4,y4) = loop4(x2,y3)

    long long x5 = x4, z5 = z3;
    loop5(&x5, &z5);   // (x5,z5) = loop5(x4,z3)

    long long y6 = y4, z6 = z5;
    loop6(&y6, &z6);   // (y6,z6) = loop6(y4,z5)

    printf("%lld\n", z6);
    return 0;
}

#include <assert.h>

int main(void) {
    int n = 42;
    int x = n;
    int y = 0;
    int z = n;

    // loop1: (x, y, z) -> (0, y + x, z)
    {
        int tx = x;
        x = 0;
        y = y + tx;
    }

    // loop2: (x, y, z) -> (x + z, y, 0)
    {
        int tz = z;
        x = x + tz;
        z = 0;
    }

    // loop3: (x, y, z) -> (x, 0, z + y)
    {
        int ty = y;
        y = 0;
        z = z + ty;
    }

    // loop4 = loop1
    {
        int tx = x;
        x = 0;
        y = y + tx;
    }

    // loop5 = loop2
    {
        int tz = z;
        x = x + tz;
        z = 0;
    }

    // loop6 = loop3
    {
        int ty = y;
        y = 0;
        z = z + ty;
    }

    assert(z == n);
    return 0;
}

