#include <stdio.h>

typedef struct { int has; unsigned int v; } Option;

Option my_id(unsigned int x, unsigned int stack) {
  if (stack == 0) return (Option){0, 0};
  if (x == 0) return (Option){1, 0};
  Option r = my_id(x - 1, stack - 1);
  if (r.has) return (Option){1, r.v + 1};
  return (Option){0, 0};
}

int main(void) {
  Option result = my_id(10, 0);
  if (result.has && result.v == 10) {
    puts("error");
    return 1;
  }
  return 0;
}

