void __VERIFIER_assume(int cond) {
    if (!cond) {
        /* in verification settings this would discard the path;
           here we simply exit to simulate unreachable assumptions */
        exit(0);
    }
}

int main(void) {
    int N;
    if (scanf("%d", &N) != 1) return 0;

    if (N <= 0) return 0;

    __VERIFIER_assume((long)N <= 2147483647L / (long)sizeof(int));

    int *a = (int *)malloc(sizeof(int) * (size_t)N);
    if (!a) return 0;

    long long sum[1];
    sum[0] = 1;

    for (int i = 0; i < N; ++i) {
        a[i] = 5;
    }

    for (int i = 0; i < N; ++i) {
        if (a[i] == 5) {
            sum[0] = sum[0] + a[i];
        } else {
            sum[0] = sum[0] * a[i];
        }
    }

    __VERIFIER_assert(sum[0] == 1 + 5LL * (long long)N);

    free(a);
    return 0;
}

