int main(void) {
    long long N;
    if (scanf("%lld", &N) != 1) return 1;
    if (N <= 0) {
        printf("0\n");
        return 0;
    }

    long long *a = malloc((size_t)N * sizeof(long long));
    if (!a) return 2;

    for (long long i = 0; i < N; ++i) a[i] = 5;

    long long sum = 0;
    for (long long i = 0; i < N; ++i) {
        if (a[i] == 5) sum = sum + a[i];
        else sum = sum * a[i];
    }

    printf("%lld\n", sum);
    free(a);
    return 0;
}

