    for (int i = 0; i < N; ++i) {
        if (i == 0) {
            sum[0] = 0;
        } else {
            int ai = (i % 2 == 0) ? 20 : 0;
            sum[0] = sum[0] + ai;
        }
    }

    assert(sum[0] <= 2 * N);
    return 0;
