void error(void) {
    fprintf(stderr, "error\n");
    exit(1);
}

int main(int argc, char **argv) {
    if (argc < 2) return 0;
    int N = atoi(argv[1]);
    if (N <= 0) return 0;

    int size = 2 * N;
    int *arr = malloc(size * sizeof(int));
    if (!arr) return 1;

    int idx = 20 * ((N - 1) / 2);
    if (idx >= size) error();

    arr[idx] = 0;

    free(arr);
    return 0;
}

